const winLoss = $('Build Stats Query').first().json.winLoss || '';
const oppStats = $('Fetch Opp Stats').first().json.content || '';
return [{ json: { command: "docker exec n8n-envision-postgres-1 psql -U n8n -d n8n -t -A -F'|' -c \"SELECT name, size_standard, threat_level, total_obligated FROM gda_competitor_watchlist ORDER BY total_obligated DESC LIMIT 35;\"", winLoss, oppStats } }];

const winLoss = $('Build Competitor Query').first().json.winLoss || 'No data';
const oppStats = $('Build Competitor Query').first().json.oppStats || 'No data';
const competitors = $('Fetch Competitors').first().json.content || 'No data';

const prompt = `You are the GDA Command AI Pattern Extractor for Envision Innovative Solutions (EIS), a defense contractor.

Analyze this historical data and extract actionable patterns.

WIN/LOSS DATA:\n${winLoss}

OPPORTUNITY STATISTICS (dept|naics|set_aside|count|avg_value|avg_score):\n${oppStats}

COMPETITOR INTELLIGENCE:\n${competitors}

Extract patterns as JSON array. Each pattern: {"pattern_type":"win_condition|loss_pattern|pricing_benchmark|competitive_advantage|agency_preference|naics_trend","pattern_name":"short name","description":"2-3 sentences","conditions":{},"historical_outcome":{"win_rate":0.0-1.0,"sample_size":0},"confidence":0-100,"actionable_insight":"what to do"}

Return 5-15 patterns. ONLY valid JSON array, no markdown.`;

return [{ json: { model: 'claude-sonnet-4-20250514', max_tokens: 4000, messages: [{ role: 'user', content: prompt }] } }];

const raw = $input.first().json.content?.[0]?.text || '[]';
let patterns;
try { patterns = JSON.parse(raw.replace(/```json|```/g, '').trim()); } catch { patterns = []; }

if (!patterns.length) return [{ json: { stored: 0, patterns: [] } }];

const esc = (s) => (s || '').replace(/'/g, "''");
const sqlParts = patterns.map(p =>
  `('${esc(p.pattern_type)}', '${esc(p.pattern_name)}', '${esc(p.description)}', '${esc(JSON.stringify(p.conditions || {}))}'::jsonb, '${esc(JSON.stringify(p.historical_outcome || {}))}'::jsonb, ${p.historical_outcome?.sample_size || 0}, ${p.confidence || 0})`
).join(',\n');

const sql = `INSERT INTO gda_pattern_library (pattern_type, pattern_name, description, conditions, historical_outcome, sample_size, confidence) VALUES ${sqlParts};`;

return [{ json: { command: `docker exec n8n-envision-postgres-1 psql -U n8n -d n8n -c \"${sql.replace(/\"/g, '\\\"')}\"`, pattern_count: patterns.length, patterns } }];
